"""
SST Trefoil Mega Script V3
==========================

Contains, in one large file:
1) the patched baseline script (kept intact in source form)
2) the Option-B sweep script (kept intact in source form)
3) a new V3 advanced block with:
   - N-convergence study
   - adaptive a-scan
   - explicit R_t/r_t optimisation on [2.0, 2.6]

Usage
-----
python sst_trefoil_mega_v3_baseline_sweep_advanced.py --mode baseline
python sst_trefoil_mega_v3_baseline_sweep_advanced.py --mode sweep
python sst_trefoil_mega_v3_baseline_sweep_advanced.py --mode advanced
python sst_trefoil_mega_v3_baseline_sweep_advanced.py --mode both
python sst_trefoil_mega_v3_baseline_sweep_advanced.py --mode all

Add --fast for a lighter smoke-test version of the advanced block.
"""

from __future__ import annotations

import argparse

BASELINE_SCRIPT = '"""\nSST Trefoil Vortex Stability Analysis — patched baseline\n=======================================================\n\nKey repairs relative to the earlier baseline:\n\n1) Gamma_0 is treated as an independent input or scan variable.\n   Nothing in the computation derives Gamma_0 from r_c_canon.\n\n2) A_K is extracted from a local slope plateau in\n      y(a) = E_BS_norm(a) / L_K\n   versus\n      x(a) = -ln(a)\n   rather than from one global linear fit across mixed regimes.\n\n3) Uses exact c = 299792458 m/s for the alpha consistency check.\n\nThe script computes:\n- dimensionless trefoil geometry\n- regularised Biot–Savart self-energy E_BS_norm(a_dimless)\n- local slope A_K_local(a)\n- plateau estimate A_K_plateau\n- stationary radius a* from the Route-2 functional\n- diagnostic chi_eff = a* v_swirl / Gamma_0\n\nImportant epistemic note:\nThis script may compare against r_c_canon, but does NOT use r_c_canon\nto define Gamma_0 or the natural length scale. Physical scaling is set by\nL_natural = Gamma_0 / v_swirl only.\n"""\n\nimport numpy as np\nfrom scipy.optimize import brentq\nimport matplotlib.pyplot as plt\nimport warnings\nwarnings.filterwarnings(\'ignore\')\n\n# ─────────────────────────────────────────────────────────────\n# 1. Canonical reference values (for comparison only)\n# ─────────────────────────────────────────────────────────────\nr_c_canon = 1.40897017e-15         # m, comparison target only\nv_swirl   = 1.09384563e6           # m/s, primitive\nrho_f     = 7.0e-7                 # kg/m^3, primitive\nrho_core  = 3.8934358266918687e18  # kg/m^3, reference only, not used in Route 2\nc_exact   = 299792458.0            # m/s, exact\n\n# Independent Gamma_0 input.\n# For a first comparison run, we choose the canonical-scale value numerically,\n# but NOT by computing it from r_c inside the algorithm.\nGamma_0_input = 9.68361918e-09     # m^2/s  <-- independent input / scan variable\n\nprint("Reference / input values:")\nprint(f"  r_c_canon   = {r_c_canon:.8e} m   (comparison only)")\nprint(f"  v_swirl     = {v_swirl:.8e} m/s")\nprint(f"  rho_f       = {rho_f:.8e} kg/m^3")\nprint(f"  rho_core    = {rho_core:.8e} kg/m^3  (not used in Route 2)")\nprint(f"  Gamma_0     = {Gamma_0_input:.8e} m^2/s  (independent input)")\nprint(f"  c           = {c_exact:.1f} m/s")\nprint()\n\n# ─────────────────────────────────────────────────────────────\n# 2. Trefoil centerline geometry (dimensionless)\n# ─────────────────────────────────────────────────────────────\nR_t = 2.0\nr_t = 1.0\nN   = 2000\n\n\ndef trefoil_points(N, R_t=2.0, r_t=1.0):\n    theta = np.linspace(0, 2*np.pi, N, endpoint=False)\n    x = (R_t + r_t * np.cos(3*theta)) * np.cos(2*theta)\n    y = (R_t + r_t * np.cos(3*theta)) * np.sin(2*theta)\n    z = r_t * np.sin(3*theta)\n    return np.stack([x, y, z], axis=1)\n\n\npts = trefoil_points(N, R_t, r_t)\ndiffs = np.roll(pts, -1, axis=0) - pts\nseg_lengths = np.linalg.norm(diffs, axis=1)\nL_K_dimless = np.sum(seg_lengths)\ntangents = diffs / seg_lengths[:, None]\n\n# coarse self-distance estimate\nstep = max(1, N // 200)\npts_coarse = pts[::step]\nn_c = len(pts_coarse)\nexclude = max(3, n_c // 20)\nd_min = np.inf\nfor i in range(n_c):\n    for j in range(i + exclude, n_c - exclude):\n        d = np.linalg.norm(pts_coarse[i] - pts_coarse[j])\n        if d < d_min:\n            d_min = d\n\n# segment spacing estimate for UV-discretisation diagnostics\nell_seg_med = np.median(seg_lengths)\n\nprint("Trefoil geometry (dimensionless):")\nprint(f"  N               = {N}")\nprint(f"  L_K             = {L_K_dimless:.8f}")\nprint(f"  d_min           = {d_min:.8f}")\nprint(f"  median ds       = {ell_seg_med:.8e}")\nprint()\n\n# ─────────────────────────────────────────────────────────────\n# 3. Regularised Biot–Savart self-energy E_BS_norm(a_dimless)\n# ─────────────────────────────────────────────────────────────\nxi = 1.0\n\n\ndef compute_E_BS_norm(a_dimless, pts, tangents, seg_lengths, xi=1.0):\n    """\n    E_BS_norm = E_BS / (rho_f * Gamma_0^2)\n    Dimensionless geometry only.\n    """\n    delta = xi * a_dimless\n    N = len(pts)\n    total = 0.0\n    index = np.arange(N)\n    for i in range(N):\n        diff = pts - pts[i]\n        dist = np.linalg.norm(diff, axis=1)\n        mask = (dist > delta) & (index != i)\n        if not np.any(mask):\n            continue\n        dot_tt = tangents[mask] @ tangents[i]\n        integrand = dot_tt / dist[mask]\n        total += np.sum(integrand * seg_lengths[mask]) * seg_lengths[i]\n    return total / (8 * np.pi)\n\n\n# Scan range:\n# start somewhat above the segment scale, otherwise the curve is mesh-flat.\na_scan = np.logspace(np.log10(max(3*ell_seg_med, d_min*1e-4)), np.log10(d_min * 0.35), 24)\n\nprint("Computing E_BS_norm(a_dimless)...")\nE_BS_vals = []\nfor a_d in a_scan:\n    e = compute_E_BS_norm(a_d, pts, tangents, seg_lengths, xi=xi)\n    E_BS_vals.append(e)\n    print(f"  a_dimless = {a_d:.6e}   E_BS_norm = {e:.8f}")\nE_BS_vals = np.array(E_BS_vals)\nprint()\n\n# ─────────────────────────────────────────────────────────────\n# 4. Local-slope extraction of A_K\n# ─────────────────────────────────────────────────────────────\n# Model: y = E_BS_norm/L_K = A_K ln(L_K/a) + a_K\n# Hence A_K = d y / d(-ln a)\n\nx = -np.log(a_scan)\ny = E_BS_vals / L_K_dimless\n\n# local finite-difference slopes and centers\nx_mid = 0.5 * (x[:-1] + x[1:])\na_mid = np.sqrt(a_scan[:-1] * a_scan[1:])\nA_local = np.diff(y) / np.diff(x)\n\n# Plateau selector:\n# keep only region where\n# - slope is positive\n# - relative change in E_BS is non-negligible (avoid mesh-flat region)\n# - a is still well below d_min (stay in slender-ish regime)\nrel_dE = np.abs(np.diff(E_BS_vals)) / np.maximum(np.abs(E_BS_vals[:-1]), 1e-300)\nplateau_mask = (A_local > 0) & (rel_dE > 1e-4) & (a_mid < 0.12 * d_min)\n\nif np.any(plateau_mask):\n    A_plateau_vals = A_local[plateau_mask]\n    A_K_plateau = np.median(A_plateau_vals)\n    A_K_spread = np.std(A_plateau_vals)\n    plateau_method = "local-slope plateau"\nelse:\n    # fallback: use the median of the first third of positive local slopes\n    pos = A_local[A_local > 0]\n    if len(pos) == 0:\n        A_K_plateau = np.nan\n        A_K_spread = np.nan\n        plateau_method = "failed"\n    else:\n        take = max(3, len(pos)//3)\n        A_K_plateau = np.median(pos[:take])\n        A_K_spread = np.std(pos[:take])\n        plateau_method = "fallback-positive-slope"\n\n# Also compute the old-style global fit as a reference only\ncoeffs = np.polyfit(x, y, 1)\nA_K_global = coeffs[0]\nintercept = coeffs[1]\na_K_global = intercept - A_K_global * np.log(L_K_dimless)\n\nprint("A_K extraction:")\nprint(f"  method                 = {plateau_method}")\nprint(f"  A_K_local_plateau      = {A_K_plateau:.8f}")\nprint(f"  spread                 = {A_K_spread:.8f}")\nprint(f"  A_K_global_fit         = {A_K_global:.8f}")\nprint(f"  A_K_req = 1/(4*pi)     = {1/(4*np.pi):.8f}")\nprint()\n\n# choose plateau estimate if finite, else fall back\nA_K_use = A_K_plateau if np.isfinite(A_K_plateau) else A_K_global\n\n# Estimate a_K from local choice by anchoring at median y over plateau region\nif np.any(plateau_mask):\n    idx_ref = np.where(plateau_mask)[0][len(np.where(plateau_mask)[0]) // 2]\n    a_ref = a_mid[idx_ref]\n    y_ref = 0.5 * (y[idx_ref] + y[idx_ref + 1])\n    a_K_use = y_ref - A_K_use * np.log(L_K_dimless / a_ref)\nelse:\n    a_K_use = a_K_global\n\nprint("Chosen Biot–Savart parameters for energy model:")\nprint(f"  A_K_use                = {A_K_use:.8f}")\nprint(f"  a_K_use                = {a_K_use:.8f}")\nprint()\n\n# ─────────────────────────────────────────────────────────────\n# 5. Physical scaling from independent Gamma_0 and v_swirl\n# ─────────────────────────────────────────────────────────────\n# Natural internal scale from primitives only:\nL_natural = Gamma_0_input / v_swirl\nL_K_phys = L_K_dimless * L_natural\nd_min_phys = d_min * L_natural\n\nprint("Physical scaling from primitives:")\nprint(f"  L_natural = Gamma_0 / v_swirl = {L_natural:.8e} m")\nprint(f"  L_K_phys  = {L_K_phys:.8e} m")\nprint(f"  d_min_phys= {d_min_phys:.8e} m")\nprint()\n\n# ─────────────────────────────────────────────────────────────\n# 6. Route-2 total energy functional\n# ─────────────────────────────────────────────────────────────\nlam_K = 0.01\np_exp = 2\n\n\ndef E_contact_phys(a, d_min_phys, lam_K, p_exp, rho_f, Gamma_0, L_K_phys):\n    if 2*a >= d_min_phys:\n        return np.inf\n    x = 2*a / (d_min_phys - 2*a)\n    return lam_K * rho_f * Gamma_0**2 * L_K_phys * x**p_exp\n\n\n\ndef E_K_phys(a, A_K, a_K, L_K_phys, Gamma_0, rho_f, v_swirl,\n             d_min_phys, lam_K=0.01, p_exp=2):\n    if a <= 0 or 2*a >= d_min_phys:\n        return np.inf\n    E_BS = rho_f * Gamma_0**2 * L_K_phys * (A_K * np.log(L_K_phys / a) + a_K)\n    E_core = (np.pi / 2) * rho_f * v_swirl**2 * a**2 * L_K_phys\n    E_cont = E_contact_phys(a, d_min_phys, lam_K, p_exp, rho_f, Gamma_0, L_K_phys)\n    return E_BS + E_core + E_cont\n\n\n\ndef dE_K_da(a, A_K, L_K_phys, Gamma_0, rho_f, v_swirl,\n            d_min_phys, lam_K=0.01, p_exp=2):\n    if a <= 0 or 2*a >= d_min_phys:\n        return np.nan\n    dE_BS = -rho_f * Gamma_0**2 * L_K_phys * A_K / a\n    dE_core = np.pi * rho_f * v_swirl**2 * a * L_K_phys\n    x = 2*a / (d_min_phys - 2*a)\n    dx_da = 2*d_min_phys / (d_min_phys - 2*a)**2\n    dE_cont = lam_K * rho_f * Gamma_0**2 * L_K_phys * p_exp * x**(p_exp - 1) * dx_da\n    return dE_BS + dE_core + dE_cont\n\n\n# analytical no-contact baseline\nif np.isfinite(A_K_use):\n    a0 = np.sqrt(A_K_use / np.pi) * Gamma_0_input / v_swirl\nelse:\n    a0 = np.nan\n\n# search stationary point\n# do not search below machine-noise scale; use a fraction of L_natural\n# and stay below self-contact threshold\na_lo = max(d_min_phys * 1e-7, L_natural * 1e-8)\na_hi = d_min_phys * 0.49\na_vals = np.logspace(np.log10(a_lo), np.log10(a_hi), 600)\ndE_vals = np.array([\n    dE_K_da(a, A_K_use, L_K_phys, Gamma_0_input, rho_f, v_swirl,\n            d_min_phys, lam_K, p_exp)\n    for a in a_vals\n])\n\nsign_changes = np.where(np.diff(np.sign(dE_vals)))[0]\na_star = np.nan\nis_minimum = False\n\nif len(sign_changes) > 0:\n    idx = sign_changes[0]\n    a_star = brentq(\n        dE_K_da, a_vals[idx], a_vals[idx + 1],\n        args=(A_K_use, L_K_phys, Gamma_0_input, rho_f, v_swirl,\n              d_min_phys, lam_K, p_exp)\n    )\n    h = max(a_star * 1e-6, 1e-30)\n    d2E_num = (\n        dE_K_da(a_star + h, A_K_use, L_K_phys, Gamma_0_input, rho_f, v_swirl,\n                d_min_phys, lam_K, p_exp)\n        - dE_K_da(a_star - h, A_K_use, L_K_phys, Gamma_0_input, rho_f, v_swirl,\n                  d_min_phys, lam_K, p_exp)\n    ) / (2*h)\n    is_minimum = d2E_num > 0\nelse:\n    valid = np.isfinite(dE_vals)\n    if np.any(valid):\n        a_star = a_vals[valid][np.argmin(np.abs(dE_vals[valid]))]\n\n# dimensionless effective closure factor\nchi_eff = a_star * v_swirl / Gamma_0_input if np.isfinite(a_star) else np.nan\nchi_req = 1 / (2 * np.pi)\n\nalpha_SST = 2 * v_swirl / c_exact\n\n# ─────────────────────────────────────────────────────────────\n# 7. Optional Gamma_0 scan (still independent)\n# ─────────────────────────────────────────────────────────────\nGamma_scan = Gamma_0_input * np.logspace(-1.0, 1.0, 21)\na_star_scan = []\nchi_scan = []\n\nfor G in Gamma_scan:\n    L_nat = G / v_swirl\n    L_phys = L_K_dimless * L_nat\n    d_phys = d_min * L_nat\n    a0_scan = np.sqrt(A_K_use / np.pi) * G / v_swirl if np.isfinite(A_K_use) else np.nan\n    # use analytical no-contact as baseline because contact term is weak in the first model\n    a_star_scan.append(a0_scan)\n    chi_scan.append(a0_scan * v_swirl / G if np.isfinite(a0_scan) else np.nan)\n\na_star_scan = np.array(a_star_scan)\nchi_scan = np.array(chi_scan)\n\n# ─────────────────────────────────────────────────────────────\n# 8. Results\n# ─────────────────────────────────────────────────────────────\nprint("=" * 70)\nprint("RESULTS SUMMARY")\nprint("=" * 70)\nprint("\\nPrimitive inputs:")\nprint(f"  rho_f         = {rho_f:.8e} kg/m^3")\nprint(f"  Gamma_0       = {Gamma_0_input:.8e} m^2/s")\nprint(f"  v_swirl       = {v_swirl:.8e} m/s")\n\nprint("\\nBiot–Savart extraction:")\nprint(f"  A_K_use       = {A_K_use:.8f}")\nprint(f"  A_K_req       = {1/(4*np.pi):.8f}")\nprint(f"  A_K_use/A_req = {A_K_use / (1/(4*np.pi)):.8f}")\nprint(f"  a_K_use       = {a_K_use:.8f}")\n\nprint("\\nStationary radius:")\nprint(f"  a0 (no contact)   = {a0:.8e} m")\nprint(f"  a* (full model)   = {a_star:.8e} m")\nprint(f"  is minimum        = {is_minimum}")\nprint(f"  a*/r_c_canon      = {a_star / r_c_canon:.8f}")\nprint(f"  chi_eff           = {chi_eff:.8f}")\nprint(f"  chi_req = 1/(2pi) = {chi_req:.8f}")\nprint(f"  chi_eff/chi_req   = {chi_eff / chi_req:.8f}")\n\nprint("\\nAlpha consistency check:")\nprint(f"  alpha_SST        = {alpha_SST:.12f}")\nprint(f"  alpha_SST^-1     = {1/alpha_SST:.9f}")\nprint("  NIST target      = 137.035999177")\nprint()\n\nif np.isfinite(a_star):\n    gap = r_c_canon / a_star\n    print("Interpretation:")\n    if abs(np.log10(a_star / r_c_canon)) < 0.1:\n        print("  ✓ a* agrees with r_c_canon within about 25%.")\n    elif abs(np.log10(a_star / r_c_canon)) < 0.3:\n        print("  ~ a* is within a factor about 2 of r_c_canon.")\n    else:\n        print("  ✗ a* differs from r_c_canon by more than a factor about 2.")\n    print(f"  multiplicative closure factor r_c_canon/a* = {gap:.8f}")\nprint()\n\n# ─────────────────────────────────────────────────────────────\n# 9. Plots\n# ─────────────────────────────────────────────────────────────\nout1 = "./sst_trefoil_AK_local_plateau.png"\nout2 = "./sst_trefoil_energy_patched.png"\nout3 = "./sst_trefoil_gamma_scan.png"\n\n# Plot 1: A_local vs a_mid\nplt.figure(figsize=(8, 5))\nplt.semilogx(a_mid, A_local, \'o-\', lw=1.5, ms=4, label=\'Local slope $A_K(a)$\')\nif np.any(plateau_mask):\n    plt.semilogx(a_mid[plateau_mask], A_local[plateau_mask], \'ro\', ms=5, label=\'Plateau region\')\nplt.axhline(1/(4*np.pi), color=\'green\', ls=\'--\', lw=1.5, label=r\'$1/(4\\pi)$\')\nif np.isfinite(A_K_use):\n    plt.axhline(A_K_use, color=\'orange\', ls=\':\', lw=2, label=f\'Chosen $A_K$ = {A_K_use:.4f}\')\nplt.xlabel(r\'$a_{\\rm dimless}$\')\nplt.ylabel(\'$A_K$ from local slope\')\nplt.title(\'Local-slope extraction of $A_K$\')\nplt.grid(True, alpha=0.3)\nplt.legend()\nplt.tight_layout()\nplt.savefig(out1, dpi=160, bbox_inches=\'tight\')\nplt.close()\n\n# Plot 2: energy and derivative\nfig, axes = plt.subplots(1, 2, figsize=(13, 5))\na_plot = np.logspace(np.log10(a_lo), np.log10(d_min_phys * 0.4), 350)\nE_plot = np.array([\n    E_K_phys(a, A_K_use, a_K_use, L_K_phys, Gamma_0_input, rho_f, v_swirl,\n             d_min_phys, lam_K, p_exp)\n    for a in a_plot\n])\ndE_plot = np.array([\n    dE_K_da(a, A_K_use, L_K_phys, Gamma_0_input, rho_f, v_swirl,\n            d_min_phys, lam_K, p_exp)\n    for a in a_plot\n])\n\nfinite_E = np.isfinite(E_plot)\nfinite_dE = np.isfinite(dE_plot)\n\naxes[0].loglog(a_plot[finite_E] / r_c_canon, E_plot[finite_E], \'b-\', lw=2)\naxes[0].axvline(1.0, color=\'red\', ls=\'--\', lw=1.5, label=\'$r_c$ canon\')\nif np.isfinite(a_star):\n    axes[0].axvline(a_star / r_c_canon, color=\'green\', ls=\':\', lw=2, label=\'$a^*$\')\naxes[0].set_xlabel(\'a / r_c_canon\')\naxes[0].set_ylabel(\'$E_K(a)$ [J]\')\naxes[0].set_title(\'Energy landscape\')\naxes[0].grid(True, alpha=0.3)\naxes[0].legend()\n\naxes[1].semilogx(a_plot[finite_dE] / r_c_canon, dE_plot[finite_dE], \'b-\', lw=2)\naxes[1].axhline(0.0, color=\'k\', lw=1)\naxes[1].axvline(1.0, color=\'red\', ls=\'--\', lw=1.5, label=\'$r_c$ canon\')\nif np.isfinite(a_star):\n    axes[1].axvline(a_star / r_c_canon, color=\'green\', ls=\':\', lw=2, label=\'$a^*$\')\naxes[1].set_xlabel(\'a / r_c_canon\')\naxes[1].set_ylabel(\'$dE/da$ [J/m]\')\naxes[1].set_title(\'Stationarity condition\')\naxes[1].grid(True, alpha=0.3)\naxes[1].legend()\n\nplt.tight_layout()\nplt.savefig(out2, dpi=160, bbox_inches=\'tight\')\nplt.close()\n\n# Plot 3: Gamma_0 scan\nplt.figure(figsize=(8, 5))\nplt.loglog(Gamma_scan, a_star_scan / r_c_canon, \'o-\', lw=1.7, ms=4, label=\'a0 / r_c_canon\')\nplt.axhline(1.0, color=\'red\', ls=\'--\', lw=1.5, label=\'a = r_c_canon\')\nplt.xlabel(r\'$\\Gamma_0$ [m$^2$/s]\')\nplt.ylabel(\'$a_0/r_c^{canon}$\')\nplt.title(r\'Independent $\\Gamma_0$ scan (no-contact baseline)\')\nplt.grid(True, alpha=0.3)\nplt.legend()\nplt.tight_layout()\nplt.savefig(out3, dpi=160, bbox_inches=\'tight\')\nplt.close()\n\nprint("Saved files:")\nprint(f"  {out1}")\nprint(f"  {out2}")\nprint(f"  {out3}")\nprint(f"  ./sst_trefoil_stability_patched.py")\n'
SWEEP_SCRIPT = '"""\nSST Trefoil Option-B Sweep\n==========================\n\nPurpose\n-------\n1) Harder Option-B test:\n   Treat Gamma_0 as an independent input and compute the dimensionless closure\n   factor chi_eff = a* v_swirl / Gamma_0.\n   Then infer the Gamma_0 required to reproduce the canonical r_c:\n       Gamma_req = r_c_canon * v_swirl / chi_eff.\n   This avoids feeding r_c into the algorithmic definition of Gamma_0.\n\n2) Small parameter study:\n   Sweep over\n     - Gamma_0\n     - trefoil geometry ratio R_t / r_t\n     - Biot-Savart cutoff xi\n     - contact barrier strength lam_K and exponent p_exp\n\nEnergy model (Route 2, rho_f only)\n----------------------------------\nE_K(a) = rho_f * Gamma_0^2 * L_K * [A_K * ln(L_K/a) + a_K]\n       + (pi/2) * rho_f * v_swirl^2 * a^2 * L_K\n       + E_contact(a)\n\nOutput\n------\n- CSV tables for the physics sweep and the contact-barrier study\n- summary text file\n- plots for closure and sensitivity\n"""\n\nfrom __future__ import annotations\n\nimport math\nimport os\nfrom dataclasses import dataclass\nfrom typing import Dict, Tuple, List\n\nimport numpy as np\nimport pandas as pd\nimport matplotlib.pyplot as plt\nfrom scipy.optimize import brentq\n\n# -----------------------------------------------------------------------------\n# Canonical comparison values (comparison only unless explicitly stated)\n# -----------------------------------------------------------------------------\nr_c_canon = 1.40897017e-15               # m\nv_swirl   = 1.09384563e6                 # m/s\nrho_f     = 7.0e-7                       # kg/m^3\nrho_core  = 3.8934358266918687e18        # kg/m^3 (not used in Route 2)\nc_exact   = 299_792_458.0                # m/s\nchi_req   = 1.0 / (2.0 * np.pi)\nA_req     = 1.0 / (4.0 * np.pi)\nGamma0_canon_numeric = 2.0 * np.pi * r_c_canon * v_swirl\nalpha_sst = 2.0 * v_swirl / c_exact\n\nOUTDIR = "./sst_optionB_outputs"\nos.makedirs(OUTDIR, exist_ok=True)\n\n# -----------------------------------------------------------------------------\n# Geometry and Biot-Savart helpers\n# -----------------------------------------------------------------------------\n\ndef trefoil_points(N: int, R_t: float, r_t: float) -> np.ndarray:\n    theta = np.linspace(0.0, 2.0 * np.pi, N, endpoint=False)\n    x = (R_t + r_t * np.cos(3.0 * theta)) * np.cos(2.0 * theta)\n    y = (R_t + r_t * np.cos(3.0 * theta)) * np.sin(2.0 * theta)\n    z = r_t * np.sin(3.0 * theta)\n    return np.stack([x, y, z], axis=1)\n\n\ndef coarse_min_self_distance(pts: np.ndarray, coarse_target: int = 160) -> float:\n    N = len(pts)\n    step = max(1, N // coarse_target)\n    pts_c = pts[::step]\n    n_c = len(pts_c)\n    exclude = max(3, n_c // 20)\n    d_min = np.inf\n    for i in range(n_c):\n        for j in range(i + exclude, n_c - exclude):\n            d = np.linalg.norm(pts_c[i] - pts_c[j])\n            if d < d_min:\n                d_min = d\n    return float(d_min)\n\n\n@dataclass\nclass GeometryData:\n    R_t: float\n    r_t: float\n    ratio: float\n    N: int\n    pts: np.ndarray\n    seg_lengths: np.ndarray\n    tangents: np.ndarray\n    L_K_dimless: float\n    d_min_dimless: float\n    ds_median: float\n    dist_matrix: np.ndarray\n    dot_matrix: np.ndarray\n    weight_matrix: np.ndarray\n    valid_offdiag: np.ndarray\n\n\ndef build_geometry(N: int, ratio: float, r_t: float = 1.0) -> GeometryData:\n    R_t = ratio * r_t\n    pts = trefoil_points(N, R_t, r_t)\n    diffs = np.roll(pts, -1, axis=0) - pts\n    seg_lengths = np.linalg.norm(diffs, axis=1)\n    tangents = diffs / seg_lengths[:, None]\n    L_K_dimless = float(np.sum(seg_lengths))\n    d_min_dimless = coarse_min_self_distance(pts)\n    ds_median = float(np.median(seg_lengths))\n\n    # pairwise matrices for fast repeated E_BS evaluation\n    diff = pts[:, None, :] - pts[None, :, :]\n    dist = np.linalg.norm(diff, axis=2)\n    dot = tangents @ tangents.T\n    weight = np.outer(seg_lengths, seg_lengths)\n    offdiag = ~np.eye(N, dtype=bool)\n    return GeometryData(\n        R_t=R_t,\n        r_t=r_t,\n        ratio=ratio,\n        N=N,\n        pts=pts,\n        seg_lengths=seg_lengths,\n        tangents=tangents,\n        L_K_dimless=L_K_dimless,\n        d_min_dimless=d_min_dimless,\n        ds_median=ds_median,\n        dist_matrix=dist,\n        dot_matrix=dot,\n        weight_matrix=weight,\n        valid_offdiag=offdiag,\n    )\n\n\ndef compute_E_BS_norm_from_mats(a_dimless: float, xi: float, geom: GeometryData) -> float:\n    delta = xi * a_dimless\n    mask = (geom.dist_matrix > delta) & geom.valid_offdiag\n    total = np.sum((geom.dot_matrix / np.where(mask, geom.dist_matrix, 1.0)) * geom.weight_matrix * mask)\n    return float(total / (8.0 * np.pi))\n\n\ndef extract_AK_local(a_scan: np.ndarray, E_vals: np.ndarray, L_K_dimless: float, d_min: float):\n    x = -np.log(a_scan)\n    y = E_vals / L_K_dimless\n    A_local = np.diff(y) / np.diff(x)\n    a_mid = np.sqrt(a_scan[:-1] * a_scan[1:])\n    rel_dE = np.abs(np.diff(E_vals)) / np.maximum(np.abs(E_vals[:-1]), 1e-300)\n\n    # plateau selector: avoid mesh-flat UV region and avoid too-large a where asymptotics deteriorate\n    plateau_mask = (A_local > 0.0) & (rel_dE > 1e-4) & (a_mid < 0.12 * d_min)\n    if np.any(plateau_mask):\n        A_vals = A_local[plateau_mask]\n        A_K = float(np.median(A_vals))\n        A_spread = float(np.std(A_vals))\n        idxs = np.where(plateau_mask)[0]\n        idx_ref = idxs[len(idxs) // 2]\n        a_ref = a_mid[idx_ref]\n        y_ref = 0.5 * (y[idx_ref] + y[idx_ref + 1])\n        a_K = float(y_ref - A_K * np.log(L_K_dimless / a_ref))\n        method = "local-plateau"\n    else:\n        coeffs = np.polyfit(x, y, 1)\n        A_K = float(coeffs[0])\n        intercept = float(coeffs[1])\n        a_K = float(intercept - A_K * np.log(L_K_dimless))\n        A_spread = float(\'nan\')\n        method = "global-fit-fallback"\n\n    coeffs_global = np.polyfit(x, y, 1)\n    A_global = float(coeffs_global[0])\n    return {\n        "A_K_use": A_K,\n        "a_K_use": a_K,\n        "A_K_spread": A_spread,\n        "method": method,\n        "A_K_global": A_global,\n        "a_mid": a_mid,\n        "A_local": A_local,\n        "plateau_mask": plateau_mask,\n        "x": x,\n        "y": y,\n    }\n\n\n# -----------------------------------------------------------------------------\n# Route-2 energy model in physical units\n# -----------------------------------------------------------------------------\n\ndef E_contact_phys(a: float, d_min_phys: float, lam_K: float, p_exp: int,\n                   rho_f: float, Gamma_0: float, L_K_phys: float) -> float:\n    if a <= 0.0 or 2.0 * a >= d_min_phys:\n        return np.inf\n    x = 2.0 * a / (d_min_phys - 2.0 * a)\n    return lam_K * rho_f * Gamma_0**2 * L_K_phys * x**p_exp\n\n\ndef dE_da(a: float, A_K: float, L_K_phys: float, Gamma_0: float, rho_f: float,\n          v_swirl: float, d_min_phys: float, lam_K: float, p_exp: int) -> float:\n    if a <= 0.0 or 2.0 * a >= d_min_phys:\n        return np.nan\n    dE_bs = -rho_f * Gamma_0**2 * L_K_phys * A_K / a\n    dE_core = np.pi * rho_f * v_swirl**2 * a * L_K_phys\n    x = 2.0 * a / (d_min_phys - 2.0 * a)\n    dx_da = 2.0 * d_min_phys / (d_min_phys - 2.0 * a)**2\n    dE_cont = lam_K * rho_f * Gamma_0**2 * L_K_phys * p_exp * x**(p_exp - 1) * dx_da\n    return dE_bs + dE_core + dE_cont\n\n\ndef stationary_radius(A_K: float, L_K_phys: float, d_min_phys: float,\n                      Gamma_0: float, rho_f: float, v_swirl: float,\n                      lam_K: float, p_exp: int):\n    a_lo = d_min_phys * 1e-6\n    a_hi = d_min_phys * 0.49\n    a_vals = np.logspace(np.log10(a_lo), np.log10(a_hi), 400)\n    dE_vals = np.array([\n        dE_da(a, A_K, L_K_phys, Gamma_0, rho_f, v_swirl, d_min_phys, lam_K, p_exp)\n        for a in a_vals\n    ])\n    sign_changes = np.where(np.diff(np.sign(dE_vals)))[0]\n    if len(sign_changes) > 0:\n        idx = sign_changes[0]\n        a_star = brentq(\n            dE_da,\n            a_vals[idx],\n            a_vals[idx + 1],\n            args=(A_K, L_K_phys, Gamma_0, rho_f, v_swirl, d_min_phys, lam_K, p_exp),\n        )\n        h = max(a_star * 1e-6, 1e-24)\n        d2 = (\n            dE_da(a_star + h, A_K, L_K_phys, Gamma_0, rho_f, v_swirl, d_min_phys, lam_K, p_exp)\n            - dE_da(a_star - h, A_K, L_K_phys, Gamma_0, rho_f, v_swirl, d_min_phys, lam_K, p_exp)\n        ) / (2.0 * h)\n        return float(a_star), bool(d2 > 0.0), float(d2)\n    idx = int(np.nanargmin(np.abs(dE_vals)))\n    return float(a_vals[idx]), False, float(\'nan\')\n\n\n# -----------------------------------------------------------------------------\n# Single-case runner\n# -----------------------------------------------------------------------------\n\ndef run_case(geom: GeometryData, xi: float, Gamma_0: float, lam_K: float, p_exp: int,\n             n_ascan: int = 18) -> Dict[str, float]:\n    a_min = max(3.0 * geom.ds_median, geom.d_min_dimless * 1e-4)\n    a_max = geom.d_min_dimless * 0.35\n    a_scan = np.logspace(np.log10(a_min), np.log10(a_max), n_ascan)\n    E_vals = np.array([compute_E_BS_norm_from_mats(a, xi, geom) for a in a_scan])\n    fit = extract_AK_local(a_scan, E_vals, geom.L_K_dimless, geom.d_min_dimless)\n\n    A_K = fit["A_K_use"]\n    a_K = fit["a_K_use"]\n\n    L_natural = Gamma_0 / v_swirl\n    L_K_phys = geom.L_K_dimless * L_natural\n    d_min_phys = geom.d_min_dimless * L_natural\n\n    a0 = math.sqrt(A_K / np.pi) * Gamma_0 / v_swirl\n    a_star, is_min, d2 = stationary_radius(A_K, L_K_phys, d_min_phys, Gamma_0, rho_f, v_swirl, lam_K, p_exp)\n\n    chi_eff = a_star * v_swirl / Gamma_0\n    gamma_required_for_rc = r_c_canon * v_swirl / chi_eff\n    gamma_required_ratio = gamma_required_for_rc / Gamma0_canon_numeric\n\n    # small barrier influence metric\n    barrier_shift = (a_star / a0) - 1.0 if a0 > 0 else np.nan\n\n    return {\n        "ratio_R_over_r": geom.ratio,\n        "R_t": geom.R_t,\n        "r_t": geom.r_t,\n        "N": geom.N,\n        "L_K_dimless": geom.L_K_dimless,\n        "d_min_dimless": geom.d_min_dimless,\n        "xi": xi,\n        "Gamma_0": Gamma_0,\n        "lam_K": lam_K,\n        "p_exp": p_exp,\n        "A_K": A_K,\n        "A_K_spread": fit["A_K_spread"],\n        "A_K_global": fit["A_K_global"],\n        "a_K": a_K,\n        "A_over_Areq": A_K / A_req,\n        "L_natural_m": L_natural,\n        "L_K_phys_m": L_K_phys,\n        "d_min_phys_m": d_min_phys,\n        "a0_m": a0,\n        "a_star_m": a_star,\n        "is_minimum": is_min,\n        "d2E": d2,\n        "a_star_over_rc": a_star / r_c_canon,\n        "chi_eff": chi_eff,\n        "chi_eff_over_chireq": chi_eff / chi_req,\n        "gamma_required_for_rc": gamma_required_for_rc,\n        "gamma_required_ratio_vs_canonical": gamma_required_ratio,\n        "barrier_shift_frac": barrier_shift,\n        "A_method": fit["method"],\n        "a_scan_min": a_scan.min(),\n        "a_scan_max": a_scan.max(),\n    }\n\n\n# -----------------------------------------------------------------------------\n# Sweeps\n# -----------------------------------------------------------------------------\nprint("Building geometry cache...", flush=True)\ngeometry_ratios = [1.8, 2.0, 2.2, 2.5]\nN_geom = 600\ngeom_cache = {ratio: build_geometry(N_geom, ratio) for ratio in geometry_ratios}\nprint("Geometry cache ready.\\n", flush=True)\n\n# Main physics sweep: Gamma_0, geometry ratio, xi with weak contact barrier\nGamma_multipliers = [0.8, 1.0, 1.2]\nGamma_values = [Gamma0_canon_numeric * m for m in Gamma_multipliers]\nxis = [0.8, 1.0, 1.2]\nlam_baseline = 0.01\np_baseline = 2\n\nphysics_rows: List[Dict[str, float]] = []\nfor ratio in geometry_ratios:\n    geom = geom_cache[ratio]\n    for xi in xis:\n        for G in Gamma_values:\n            physics_rows.append(run_case(geom, xi, G, lam_baseline, p_baseline))\n\nphysics_df = pd.DataFrame(physics_rows)\nphysics_csv = os.path.join(OUTDIR, "sst_optionB_physics_sweep.csv")\nphysics_df.to_csv(physics_csv, index=False)\n\n# Contact-barrier study around the nominal geometry/cutoff/gamma\ncontact_rows: List[Dict[str, float]] = []\ngeom_nom = geom_cache[2.0]\nfor lam in [0.0, 0.005, 0.01, 0.05]:\n    for pexp in [2, 4]:\n        contact_rows.append(run_case(geom_nom, 1.0, Gamma0_canon_numeric, lam, pexp))\n\ncontact_df = pd.DataFrame(contact_rows)\ncontact_csv = os.path.join(OUTDIR, "sst_optionB_contact_study.csv")\ncontact_df.to_csv(contact_csv, index=False)\n\n# -----------------------------------------------------------------------------\n# Summary diagnostics\n# -----------------------------------------------------------------------------\nsummary_lines = []\nsummary_lines.append("SST Option-B sweep summary")\nsummary_lines.append("=" * 70)\nsummary_lines.append(f"r_c_canon = {r_c_canon:.12e} m")\nsummary_lines.append(f"v_swirl   = {v_swirl:.12e} m/s")\nsummary_lines.append(f"rho_f     = {rho_f:.12e} kg/m^3")\nsummary_lines.append(f"Gamma0_canonical_numeric = {Gamma0_canon_numeric:.12e} m^2/s")\nsummary_lines.append(f"alpha_SST = {alpha_sst:.12e}")\nsummary_lines.append(f"alpha_SST^-1 = {1.0/alpha_sst:.12f}")\nsummary_lines.append("")\n\n# Best closure cases by chi_eff and by a_star/rc\nphysics_df["closure_error_chi"] = np.abs(physics_df["chi_eff_over_chireq"] - 1.0)\nphysics_df["closure_error_a"] = np.abs(physics_df["a_star_over_rc"] - 1.0)\n\nbest_chi = physics_df.sort_values("closure_error_chi").iloc[0]\nbest_a = physics_df.sort_values("closure_error_a").iloc[0]\nsummary_lines.append("Best case by chi closure:")\nsummary_lines.append(best_chi.to_string())\nsummary_lines.append("")\nsummary_lines.append("Best case by a*/r_c closure:")\nsummary_lines.append(best_a.to_string())\nsummary_lines.append("")\n\n# Nominal case summary\nnom_mask = (\n    np.abs(physics_df["ratio_R_over_r"] - 2.0) < 1e-12\n    ) & (\n    np.abs(physics_df["xi"] - 1.0) < 1e-12\n    ) & (\n    np.abs(physics_df["Gamma_0"] - Gamma0_canon_numeric) < 1e-18\n)\nnom = physics_df[nom_mask].iloc[0]\nsummary_lines.append("Nominal case (R/r=2.0, xi=1.0, Gamma0=canonical numeric value):")\nsummary_lines.append(nom.to_string())\nsummary_lines.append("")\n\nsummary_lines.append("Contact study:")\nsummary_lines.append(contact_df.to_string(index=False))\nsummary_lines.append("")\n\nsummary_path = os.path.join(OUTDIR, "sst_optionB_summary.txt")\nwith open(summary_path, "w", encoding="utf-8") as f:\n    f.write("\\n".join(summary_lines))\n\n# -----------------------------------------------------------------------------\n# Plots\n# -----------------------------------------------------------------------------\n# 1) Heatmap of chi_eff/chi_req for nominal Gamma0 across geometry ratio and xi\nnomG = Gamma0_canon_numeric\nsub = physics_df[np.abs(physics_df["Gamma_0"] - nomG) < 1e-18].copy()\nif len(sub) == 0:\n    sub = physics_df.iloc[(physics_df["Gamma_0"] - nomG).abs().argsort()[:len(geometry_ratios)*len(xis)]].copy()\nsub = sub.groupby(["ratio_R_over_r", "xi"], as_index=False)[["chi_eff_over_chireq", "A_over_Areq"]].mean()\npivot_chi = sub.pivot(index="ratio_R_over_r", columns="xi", values="chi_eff_over_chireq")\npivot_A = sub.pivot(index="ratio_R_over_r", columns="xi", values="A_over_Areq")\n\nfig, axes = plt.subplots(1, 2, figsize=(12, 5))\nfor ax, piv, title in [\n    (axes[0], pivot_chi, r"$\\chi_{\\rm eff}/\\chi_{\\rm req}$"),\n    (axes[1], pivot_A, r"$A_K/A_{\\rm req}$"),\n]:\n    im = ax.imshow(piv.values, origin="lower", aspect="auto")\n    ax.set_xticks(range(len(piv.columns)))\n    ax.set_xticklabels([f"{c:.1f}" for c in piv.columns])\n    ax.set_yticks(range(len(piv.index)))\n    ax.set_yticklabels([f"{i:.1f}" for i in piv.index])\n    ax.set_xlabel(r"cutoff $\\xi$")\n    ax.set_ylabel(r"geometry ratio $R_t/r_t$")\n    ax.set_title(title)\n    for i in range(piv.shape[0]):\n        for j in range(piv.shape[1]):\n            ax.text(j, i, f"{piv.values[i, j]:.3f}", ha="center", va="center", color="white", fontsize=9)\n    fig.colorbar(im, ax=ax, fraction=0.046, pad=0.04)\nplt.tight_layout()\nplot1 = os.path.join(OUTDIR, "sst_optionB_heatmaps.png")\nplt.savefig(plot1, dpi=160, bbox_inches="tight")\nplt.close(fig)\n\n# 2) Gamma sweep: a*/Gamma0 and chi_eff for nominal geometry/cutoff\nsub_nom = physics_df[(np.abs(physics_df["ratio_R_over_r"] - 2.0) < 1e-12) & (np.abs(physics_df["xi"] - 1.0) < 1e-12)].copy()\nsub_nom = sub_nom.sort_values("Gamma_0")\nfig, ax1 = plt.subplots(figsize=(8, 5))\nax1.plot(sub_nom["Gamma_0"], sub_nom["a_star_m"] / sub_nom["Gamma_0"], marker="o", label=r"$a^*/\\Gamma_0$")\nax1.set_xlabel(r"$\\Gamma_0$ [m$^2$/s]")\nax1.set_ylabel(r"$a^*/\\Gamma_0$ [s/m]")\nax1.grid(True, alpha=0.3)\nax2 = ax1.twinx()\nax2.plot(sub_nom["Gamma_0"], sub_nom["chi_eff_over_chireq"], marker="s", color="tab:red", label=r"$\\chi_{\\rm eff}/\\chi_{\\rm req}$")\nax2.set_ylabel(r"$\\chi_{\\rm eff}/\\chi_{\\rm req}$")\nax2.axhline(1.0, color="tab:red", ls="--", lw=1)\nlines1, labels1 = ax1.get_legend_handles_labels()\nlines2, labels2 = ax2.get_legend_handles_labels()\nax1.legend(lines1 + lines2, labels1 + labels2, loc="best")\nplt.title("Gamma sweep at nominal geometry/cutoff")\nplt.tight_layout()\nplot2 = os.path.join(OUTDIR, "sst_optionB_gamma_sweep.png")\nplt.savefig(plot2, dpi=160, bbox_inches="tight")\nplt.close(fig)\n\n# 3) Contact study plot\nfig, ax = plt.subplots(figsize=(8, 5))\nfor pexp in sorted(contact_df["p_exp"].unique()):\n    subc = contact_df[contact_df["p_exp"] == pexp].sort_values("lam_K")\n    ax.plot(subc["lam_K"], subc["a_star_over_rc"], marker="o", label=fr"$p={pexp}$")\nax.axhline(1.0, color="k", ls="--", lw=1)\nax.set_xlabel(r"contact strength $\\lambda_K$")\nax.set_ylabel(r"$a^*/r_c$")\nax.set_title("Contact-barrier sensitivity (nominal geometry/cutoff)")\nax.grid(True, alpha=0.3)\nax.legend()\nplt.tight_layout()\nplot3 = os.path.join(OUTDIR, "sst_optionB_contact_sensitivity.png")\nplt.savefig(plot3, dpi=160, bbox_inches="tight")\nplt.close(fig)\n\n# 4) Local-slope diagnostic plot for nominal geometry/cutoff/Gamma0\n# recompute nominal fit arrays for plotting\ngeom = geom_nom\na_min = max(3.0 * geom.ds_median, geom.d_min_dimless * 1e-4)\na_max = geom.d_min_dimless * 0.35\na_scan_nom = np.logspace(np.log10(a_min), np.log10(a_max), 18)\nE_vals_nom = np.array([compute_E_BS_norm_from_mats(a, 1.0, geom) for a in a_scan_nom])\nfit_nom = extract_AK_local(a_scan_nom, E_vals_nom, geom.L_K_dimless, geom.d_min_dimless)\nfig, ax = plt.subplots(figsize=(8, 5))\nax.semilogx(fit_nom["a_mid"], fit_nom["A_local"], marker="o", label=r"local $A_K(a)$")\nmask = fit_nom["plateau_mask"]\nif np.any(mask):\n    ax.semilogx(fit_nom["a_mid"][mask], fit_nom["A_local"][mask], \'ro\', label=\'plateau points\')\nax.axhline(A_req, color="green", ls="--", lw=1.5, label=r"$1/(4\\pi)$")\nax.axhline(fit_nom["A_K_use"], color="tab:red", ls=":", lw=1.5, label=fr"chosen $A_K={fit_nom[\'A_K_use\']:.4f}$")\nax.set_xlabel(r"$a$ (dimensionless)")\nax.set_ylabel(r"local $A_K$")\nax.set_title("Nominal local-slope plateau diagnostic")\nax.grid(True, alpha=0.3)\nax.legend()\nplt.tight_layout()\nplot4 = os.path.join(OUTDIR, "sst_optionB_AK_local_nominal.png")\nplt.savefig(plot4, dpi=160, bbox_inches="tight")\nplt.close(fig)\n\n# console summary\nprint("Saved files:")\nfor p in [physics_csv, contact_csv, summary_path, plot1, plot2, plot3, plot4]:\n    print(f"  {p}")\n\nprint("\\nNominal case summary:")\nprint(nom.to_string())\nprint("\\nBest closure case (by chi):")\nprint(best_chi.to_string())\n'
ADVANCED_SCRIPT = '\n"""\nSST Trefoil V3 Advanced Block\n=============================\nAdds three harder Option-B tests on top of the intact legacy baseline/sweep:\n\n1) N-convergence study\n2) adaptive a-scan with local A_K plateau detection\n3) explicit R_t/r_t optimisation on [2.0, 2.6]\n\nThe block keeps Gamma_0 as an independent input. It reports the dimensionless\nclosure factor chi_eff = a* v_swirl / Gamma_0 and compares it to 1/(2*pi)\nwithout feeding r_c back into Gamma_0.\n"""\n\nfrom __future__ import annotations\n\nimport math\nimport os\nimport warnings\nfrom dataclasses import dataclass\nfrom typing import Dict, List, Tuple\n\nimport matplotlib.pyplot as plt\nimport numpy as np\nimport pandas as pd\nfrom scipy.optimize import brentq\n\nwarnings.filterwarnings("ignore")\n\nFAST_MODE = bool(globals().get("FAST_MODE", False))\nOUTPUT_DIR = globals().get("ADV_OUTPUT_DIR", "./sst_optionB_v3_outputs")\nos.makedirs(OUTPUT_DIR, exist_ok=True)\n\n# Canon comparison values (comparison only; not used to define Gamma_0)\nr_c_canon = 1.40897017e-15\nv_swirl = 1.09384563e6\nrho_f = 7.0e-7\nc_exact = 299792458.0\nGamma0_nominal = 9.68361918e-09  # independent input chosen equal to previous nominal run for comparability\nchi_req = 1.0 / (2.0 * np.pi)\nA_req = 1.0 / (4.0 * np.pi)\nalpha_SST = 2.0 * v_swirl / c_exact\n\n@dataclass\nclass AdvConfig:\n    N_values: Tuple[int, ...]\n    rt_ratios: Tuple[float, ...]\n    xi_values: Tuple[float, ...]\n    gamma_multipliers: Tuple[float, ...]\n    lam_values: Tuple[float, ...]\n    p_values: Tuple[int, ...]\n    coarse_points: int\n    refine_points: int\n    plateau_tol: float\n    plateau_max_frac: float\n    a_min_factor: float\n    a_max_factor: float\n    nominal_rt_ratio: float\n    nominal_xi: float\n    nominal_lam: float\n    nominal_p: int\n    nominal_N: int\n\nif FAST_MODE:\n    CFG = AdvConfig(\n        N_values=(1200, 2400),\n        rt_ratios=tuple(np.round(np.arange(2.0, 2.61, 0.2), 2)),\n        xi_values=(0.8, 1.0, 1.2),\n        gamma_multipliers=(0.8, 1.0, 1.2),\n        lam_values=(0.0, 0.01, 0.05),\n        p_values=(2, 3),\n        coarse_points=18,\n        refine_points=14,\n        plateau_tol=0.15,\n        plateau_max_frac=0.12,\n        a_min_factor=1e-5,\n        a_max_factor=0.32,\n        nominal_rt_ratio=2.0,\n        nominal_xi=1.0,\n        nominal_lam=0.01,\n        nominal_p=2,\n        nominal_N=2400,\n    )\nelse:\n    CFG = AdvConfig(\n        N_values=(2000, 4000, 8000),\n        rt_ratios=tuple(np.round(np.arange(2.0, 2.61, 0.1), 2)),\n        xi_values=(0.8, 1.0, 1.2),\n        gamma_multipliers=(0.7, 0.85, 1.0, 1.15, 1.3),\n        lam_values=(0.0, 0.01, 0.05),\n        p_values=(2, 3),\n        coarse_points=24,\n        refine_points=20,\n        plateau_tol=0.12,\n        plateau_max_frac=0.10,\n        a_min_factor=1e-5,\n        a_max_factor=0.32,\n        nominal_rt_ratio=2.0,\n        nominal_xi=1.0,\n        nominal_lam=0.01,\n        nominal_p=2,\n        nominal_N=4000,\n    )\n\n_GEOM_CACHE: Dict[Tuple[int, float], dict] = {}\n_AK_CACHE: Dict[Tuple[int, float, float], dict] = {}\n\n\ndef trefoil_points(N: int, rt_ratio: float, r_minor: float = 1.0) -> np.ndarray:\n    R_major = rt_ratio * r_minor\n    theta = np.linspace(0.0, 2.0 * np.pi, N, endpoint=False)\n    x = (R_major + r_minor * np.cos(3.0 * theta)) * np.cos(2.0 * theta)\n    y = (R_major + r_minor * np.cos(3.0 * theta)) * np.sin(2.0 * theta)\n    z = r_minor * np.sin(3.0 * theta)\n    return np.stack([x, y, z], axis=1)\n\n\ndef get_geometry(N: int, rt_ratio: float) -> dict:\n    key = (int(N), float(rt_ratio))\n    if key in _GEOM_CACHE:\n        return _GEOM_CACHE[key]\n\n    pts = trefoil_points(N, rt_ratio)\n    diffs = np.roll(pts, -1, axis=0) - pts\n    seg_lengths = np.linalg.norm(diffs, axis=1)\n    tangents = diffs / seg_lengths[:, None]\n    L_dimless = float(np.sum(seg_lengths))\n\n    # minimum self-distance on a coarser subset\n    step = max(1, N // 300)\n    pts_c = pts[::step]\n    n_c = len(pts_c)\n    exclude = max(3, n_c // 20)\n    dmin = np.inf\n    for i in range(n_c):\n        j0 = i + exclude\n        j1 = max(j0, n_c - exclude)\n        for j in range(j0, j1):\n            d = np.linalg.norm(pts_c[i] - pts_c[j])\n            if d < dmin:\n                dmin = d\n\n    out = {\n        "pts": pts,\n        "seg_lengths": seg_lengths,\n        "tangents": tangents,\n        "L_dimless": L_dimless,\n        "dmin": float(dmin),\n    }\n    _GEOM_CACHE[key] = out\n    return out\n\n\ndef compute_E_BS_norm(a_dimless: float, geom: dict, xi: float = 1.0) -> float:\n    pts = geom["pts"]\n    tangents = geom["tangents"]\n    seg_lengths = geom["seg_lengths"]\n    delta = xi * a_dimless\n    N = len(pts)\n    total = 0.0\n    idx = np.arange(N)\n    for i in range(N):\n        diff = pts - pts[i]\n        dist = np.linalg.norm(diff, axis=1)\n        mask = (dist > delta) & (idx != i)\n        if not np.any(mask):\n            continue\n        dot_tt = tangents[mask] @ tangents[i]\n        total += np.sum((dot_tt / dist[mask]) * seg_lengths[mask]) * seg_lengths[i]\n    return total / (8.0 * np.pi)\n\n\ndef local_slopes(a_vals: np.ndarray, E_vals: np.ndarray, L_dimless: float) -> Tuple[np.ndarray, np.ndarray]:\n    x = -np.log(a_vals)\n    y = E_vals / L_dimless\n    A_local = np.diff(y) / np.diff(x)\n    a_mid = np.sqrt(a_vals[:-1] * a_vals[1:])\n    return a_mid, A_local\n\n\ndef longest_segments(mask: np.ndarray) -> List[Tuple[int, int]]:\n    segs: List[Tuple[int, int]] = []\n    start = None\n    for i, flag in enumerate(mask):\n        if flag and start is None:\n            start = i\n        elif not flag and start is not None:\n            segs.append((start, i - 1))\n            start = None\n    if start is not None:\n        segs.append((start, len(mask) - 1))\n    return segs\n\n\ndef choose_plateau(a_mid: np.ndarray, A_local: np.ndarray, dmin: float, tol: float, max_frac: float) -> dict:\n    # ignore UV-discretisation-zero slopes and very large-a breakdown\n    base_mask = (A_local > 1e-5) & (a_mid < max_frac * dmin)\n    if np.sum(base_mask) < 3:\n        base_mask = (A_local > 1e-5) & (a_mid < 0.2 * dmin)\n    if np.sum(base_mask) < 3:\n        # fallback: strongest positive finite local slopes\n        pos = np.where(np.isfinite(A_local) & (A_local > 0))[0]\n        if len(pos) == 0:\n            return {"ok": False}\n        idx = pos[: min(4, len(pos))]\n        vals = A_local[idx]\n        return {\n            "ok": True,\n            "indices": idx,\n            "A_use": float(np.median(vals)),\n            "plateau_relstd": float(np.std(vals) / abs(np.mean(vals))) if np.mean(vals) != 0 else np.inf,\n            "a_lo": float(a_mid[idx[0]]),\n            "a_hi": float(a_mid[idx[-1]]),\n        }\n\n    idxs = np.where(base_mask)[0]\n    best = None\n    for length in range(min(8, len(idxs)), 2, -1):\n        for j in range(0, len(idxs) - length + 1):\n            window = idxs[j : j + length]\n            if np.any(np.diff(window) != 1):\n                continue\n            vals = A_local[window]\n            relstd = float(np.std(vals) / abs(np.mean(vals))) if np.mean(vals) != 0 else np.inf\n            if relstd <= tol:\n                score = (relstd, -length)\n                if best is None or score < best[0]:\n                    best = (score, window)\n        if best is not None:\n            break\n\n    if best is None:\n        # choose most stable contiguous segment among base candidates\n        segs = longest_segments(base_mask)\n        if not segs:\n            return {"ok": False}\n        scored = []\n        for s0, s1 in segs:\n            vals = A_local[s0 : s1 + 1]\n            if len(vals) < 2:\n                continue\n            relstd = float(np.std(vals) / abs(np.mean(vals))) if np.mean(vals) != 0 else np.inf\n            scored.append((relstd, -(s1 - s0 + 1), np.arange(s0, s1 + 1)))\n        if not scored:\n            return {"ok": False}\n        scored.sort(key=lambda t: (t[0], t[1]))\n        window = scored[0][2]\n    else:\n        window = best[1]\n\n    vals = A_local[window]\n    return {\n        "ok": True,\n        "indices": window,\n        "A_use": float(np.median(vals)),\n        "plateau_relstd": float(np.std(vals) / abs(np.mean(vals))) if np.mean(vals) != 0 else np.inf,\n        "a_lo": float(a_mid[window[0]]),\n        "a_hi": float(a_mid[window[-1]]),\n    }\n\n\ndef adaptive_AK(N: int, rt_ratio: float, xi: float, cfg: AdvConfig) -> dict:\n    key = (int(N), float(rt_ratio), float(xi))\n    if key in _AK_CACHE:\n        return _AK_CACHE[key]\n\n    geom = get_geometry(N, rt_ratio)\n    dmin = geom["dmin"]\n    L_dimless = geom["L_dimless"]\n\n    a0 = np.logspace(np.log10(dmin * cfg.a_min_factor), np.log10(dmin * cfg.a_max_factor), cfg.coarse_points)\n    E0 = np.array([compute_E_BS_norm(a, geom, xi=xi) for a in a0])\n    amid0, A0 = local_slopes(a0, E0, L_dimless)\n    plateau0 = choose_plateau(amid0, A0, dmin, cfg.plateau_tol, cfg.plateau_max_frac)\n\n    if plateau0.get("ok", False):\n        lo = max(dmin * cfg.a_min_factor, plateau0["a_lo"] / 1.8)\n        hi = min(dmin * cfg.a_max_factor, plateau0["a_hi"] * 1.8)\n    else:\n        lo = dmin * cfg.a_min_factor\n        hi = min(dmin * cfg.a_max_factor, dmin * 0.08)\n\n    a1 = np.logspace(np.log10(lo), np.log10(hi), cfg.refine_points)\n    a_all = np.unique(np.sort(np.concatenate([a0, a1])))\n    E_all = np.array([compute_E_BS_norm(a, geom, xi=xi) for a in a_all])\n    amid, A_local = local_slopes(a_all, E_all, L_dimless)\n    plateau = choose_plateau(amid, A_local, dmin, cfg.plateau_tol, cfg.plateau_max_frac)\n\n    if plateau.get("ok", False):\n        A_use = plateau["A_use"]\n        idx = plateau["indices"]\n        aK_vals = (E_all[:-1][idx] / L_dimless) - A_local[idx] * np.log(L_dimless / a_all[:-1][idx])\n        a_K_use = float(np.median(aK_vals)) if len(aK_vals) else 0.0\n        plateau_relstd = plateau["plateau_relstd"]\n    else:\n        # global fallback\n        x = -np.log(a_all)\n        y = E_all / L_dimless\n        m, b = np.polyfit(x, y, 1)\n        A_use = float(m)\n        a_K_use = float(b - m * np.log(L_dimless))\n        plateau_relstd = np.inf\n\n    out = {\n        "geom": geom,\n        "a_all": a_all,\n        "E_all": E_all,\n        "a_mid": amid,\n        "A_local": A_local,\n        "A_use": float(A_use),\n        "a_K_use": float(a_K_use),\n        "plateau_relstd": float(plateau_relstd),\n        "plateau": plateau,\n    }\n    _AK_CACHE[key] = out\n    return out\n\n\ndef dE_da(a: float, A_K: float, L_phys: float, Gamma0: float, rho_f: float, v_swirl: float, dmin_phys: float, lam: float, p_exp: int) -> float:\n    if a <= 0 or 2 * a >= dmin_phys:\n        return np.nan\n    dE_bs = -rho_f * Gamma0**2 * L_phys * A_K / a\n    dE_core = np.pi * rho_f * v_swirl**2 * a * L_phys\n    if lam <= 0:\n        dE_cont = 0.0\n    else:\n        x = 2 * a / (dmin_phys - 2 * a)\n        dx_da = 2 * dmin_phys / (dmin_phys - 2 * a) ** 2\n        dE_cont = lam * rho_f * Gamma0**2 * L_phys * p_exp * x ** (p_exp - 1) * dx_da\n    return dE_bs + dE_core + dE_cont\n\n\ndef solve_stationary(A_K: float, geom: dict, Gamma0: float, lam: float, p_exp: int) -> dict:\n    L_natural = Gamma0 / v_swirl\n    L_phys = geom["L_dimless"] * L_natural\n    dmin_phys = geom["dmin"] * L_natural\n    a_lo = dmin_phys * 1e-6\n    a_hi = dmin_phys * 0.49\n    a_grid = np.logspace(np.log10(a_lo), np.log10(a_hi), 500)\n    dE_grid = np.array([dE_da(a, A_K, L_phys, Gamma0, rho_f, v_swirl, dmin_phys, lam, p_exp) for a in a_grid])\n    idx = np.where(np.diff(np.sign(dE_grid)))[0]\n    if len(idx):\n        i = idx[0]\n        a_star = float(brentq(dE_da, a_grid[i], a_grid[i + 1], args=(A_K, L_phys, Gamma0, rho_f, v_swirl, dmin_phys, lam, p_exp)))\n    else:\n        valid = np.isfinite(dE_grid)\n        if not np.any(valid):\n            a_star = float("nan")\n        else:\n            i = int(np.argmin(np.abs(dE_grid[valid])))\n            a_star = float(a_grid[valid][i])\n\n    a0 = math.sqrt(max(A_K, 0.0) / np.pi) * Gamma0 / v_swirl\n    chi_eff = a_star * v_swirl / Gamma0 if np.isfinite(a_star) else np.nan\n    return {\n        "L_phys": L_phys,\n        "dmin_phys": dmin_phys,\n        "a_star": a_star,\n        "a0": a0,\n        "chi_eff": chi_eff,\n        "chi_ratio": chi_eff / chi_req if np.isfinite(chi_eff) else np.nan,\n        "a_ratio": a_star / r_c_canon if np.isfinite(a_star) else np.nan,\n        "contact_ratio": (2 * a_star / dmin_phys) if np.isfinite(a_star) else np.nan,\n    }\n\n\ndef run_nominal_diagnostic() -> dict:\n    ak = adaptive_AK(CFG.nominal_N, CFG.nominal_rt_ratio, CFG.nominal_xi, CFG)\n    sol = solve_stationary(ak["A_use"], ak["geom"], Gamma0_nominal, CFG.nominal_lam, CFG.nominal_p)\n\n    fig, ax = plt.subplots(1, 1, figsize=(8, 5))\n    ax.semilogx(ak["a_mid"] / ak["geom"]["dmin"], ak["A_local"], "o-", ms=4, lw=1.5)\n    ax.axhline(ak["A_use"], color="tab:red", ls="--", lw=1.5, label=f"A_use={ak[\'A_use\']:.5f}")\n    ax.axhline(A_req, color="tab:green", ls=":", lw=1.5, label=f"1/(4π)={A_req:.5f}")\n    if ak["plateau"].get("ok", False):\n        ax.axvspan(ak["plateau"]["a_lo"] / ak["geom"]["dmin"], ak["plateau"]["a_hi"] / ak["geom"]["dmin"], color="gold", alpha=0.25, label="plateau window")\n    ax.set_xlabel(r"$a/d_{\\min}$")\n    ax.set_ylabel(r"$A_K^{\\rm local}$")\n    ax.set_title("Nominal adaptive plateau diagnostic")\n    ax.grid(True, alpha=0.3)\n    ax.legend()\n    plt.tight_layout()\n    fig.savefig(os.path.join(OUTPUT_DIR, "v3_nominal_adaptive_plateau.png"), dpi=160, bbox_inches="tight")\n    plt.close(fig)\n\n    return {**ak, **sol}\n\n\ndef run_N_convergence() -> pd.DataFrame:\n    rows = []\n    for N in CFG.N_values:\n        ak = adaptive_AK(N, CFG.nominal_rt_ratio, CFG.nominal_xi, CFG)\n        sol = solve_stationary(ak["A_use"], ak["geom"], Gamma0_nominal, CFG.nominal_lam, CFG.nominal_p)\n        rows.append({\n            "N": N,\n            "rt_ratio": CFG.nominal_rt_ratio,\n            "xi": CFG.nominal_xi,\n            "A_K": ak["A_use"],\n            "A_ratio": ak["A_use"] / A_req,\n            "plateau_relstd": ak["plateau_relstd"],\n            "a_star": sol["a_star"],\n            "chi_eff": sol["chi_eff"],\n            "chi_ratio": sol["chi_ratio"],\n            "a_ratio": sol["a_ratio"],\n            "contact_ratio": sol["contact_ratio"],\n        })\n    df = pd.DataFrame(rows)\n    df.to_csv(os.path.join(OUTPUT_DIR, "v3_N_convergence.csv"), index=False)\n\n    fig, ax = plt.subplots(1, 2, figsize=(11, 4.5))\n    ax[0].plot(df["N"], df["A_ratio"], "o-", lw=2)\n    ax[0].axhline(1.0, color="tab:red", ls="--")\n    ax[0].set_xlabel("N")\n    ax[0].set_ylabel(r"$A_K / (1/4\\pi)$")\n    ax[0].grid(True, alpha=0.3)\n\n    ax[1].plot(df["N"], df["chi_ratio"], "o-", lw=2)\n    ax[1].axhline(1.0, color="tab:red", ls="--")\n    ax[1].set_xlabel("N")\n    ax[1].set_ylabel(r"$\\chi_{\\rm eff} / (1/2\\pi)$")\n    ax[1].grid(True, alpha=0.3)\n    plt.tight_layout()\n    fig.savefig(os.path.join(OUTPUT_DIR, "v3_N_convergence.png"), dpi=160, bbox_inches="tight")\n    plt.close(fig)\n    return df\n\n\ndef run_ratio_optimisation() -> pd.DataFrame:\n    rows = []\n    Nopt = CFG.nominal_N\n    for ratio in CFG.rt_ratios:\n        for xi in CFG.xi_values:\n            ak = adaptive_AK(Nopt, ratio, xi, CFG)\n            sol = solve_stationary(ak["A_use"], ak["geom"], Gamma0_nominal, CFG.nominal_lam, CFG.nominal_p)\n            objective = abs(sol["chi_ratio"] - 1.0) + 0.35 * min(10.0, ak["plateau_relstd"]) + 0.15 * max(0.0, sol["contact_ratio"] - 0.5)\n            rows.append({\n                "N": Nopt,\n                "rt_ratio": ratio,\n                "xi": xi,\n                "A_K": ak["A_use"],\n                "A_ratio": ak["A_use"] / A_req,\n                "plateau_relstd": ak["plateau_relstd"],\n                "a_star": sol["a_star"],\n                "chi_eff": sol["chi_eff"],\n                "chi_ratio": sol["chi_ratio"],\n                "a_ratio": sol["a_ratio"],\n                "contact_ratio": sol["contact_ratio"],\n                "objective": objective,\n            })\n    df = pd.DataFrame(rows).sort_values(["objective", "rt_ratio", "xi"]).reset_index(drop=True)\n    df.to_csv(os.path.join(OUTPUT_DIR, "v3_rt_ratio_optimisation.csv"), index=False)\n\n    # heatmaps\n    piv1 = df.pivot(index="rt_ratio", columns="xi", values="chi_ratio")\n    piv2 = df.pivot(index="rt_ratio", columns="xi", values="A_ratio")\n    fig, ax = plt.subplots(1, 2, figsize=(11, 5))\n    im1 = ax[0].imshow(piv1.values, origin="lower", aspect="auto")\n    ax[0].set_xticks(range(len(piv1.columns)), [str(c) for c in piv1.columns])\n    ax[0].set_yticks(range(len(piv1.index)), [str(i) for i in piv1.index])\n    ax[0].set_title(r"$\\chi_{\\rm eff}/(1/2\\pi)$")\n    ax[0].set_xlabel(r"$\\xi$")\n    ax[0].set_ylabel(r"$R_t/r_t$")\n    fig.colorbar(im1, ax=ax[0], shrink=0.85)\n\n    im2 = ax[1].imshow(piv2.values, origin="lower", aspect="auto")\n    ax[1].set_xticks(range(len(piv2.columns)), [str(c) for c in piv2.columns])\n    ax[1].set_yticks(range(len(piv2.index)), [str(i) for i in piv2.index])\n    ax[1].set_title(r"$A_K/(1/4\\pi)$")\n    ax[1].set_xlabel(r"$\\xi$")\n    ax[1].set_ylabel(r"$R_t/r_t$")\n    fig.colorbar(im2, ax=ax[1], shrink=0.85)\n    plt.tight_layout()\n    fig.savefig(os.path.join(OUTPUT_DIR, "v3_rt_ratio_heatmaps.png"), dpi=160, bbox_inches="tight")\n    plt.close(fig)\n\n    # objective curve at xi nominal\n    dfn = df[np.isclose(df["xi"], CFG.nominal_xi)].copy().sort_values("rt_ratio")\n    fig2, ax2 = plt.subplots(figsize=(7.5, 4.5))\n    ax2.plot(dfn["rt_ratio"], dfn["objective"], "o-", lw=2, label="objective")\n    ax2.plot(dfn["rt_ratio"], np.abs(dfn["chi_ratio"] - 1.0), "s--", lw=1.5, label=r"$|\\chi_{eff}/(1/2\\pi)-1|$")\n    ax2.set_xlabel(r"$R_t/r_t$")\n    ax2.set_ylabel("objective")\n    ax2.set_title(r"$R_t/r_t$ optimisation (nominal $\\xi$)")\n    ax2.grid(True, alpha=0.3)\n    ax2.legend()\n    plt.tight_layout()\n    fig2.savefig(os.path.join(OUTPUT_DIR, "v3_rt_ratio_objective.png"), dpi=160, bbox_inches="tight")\n    plt.close(fig2)\n    return df\n\n\ndef run_gamma_scan(best_ratio: float, best_xi: float) -> pd.DataFrame:\n    rows = []\n    ak = adaptive_AK(CFG.nominal_N, best_ratio, best_xi, CFG)\n    for mult in CFG.gamma_multipliers:\n        Gamma0 = Gamma0_nominal * mult\n        sol = solve_stationary(ak["A_use"], ak["geom"], Gamma0, CFG.nominal_lam, CFG.nominal_p)\n        Gamma_req = r_c_canon * v_swirl / sol["chi_eff"] if np.isfinite(sol["chi_eff"]) and sol["chi_eff"] != 0 else np.nan\n        rows.append({\n            "Gamma0": Gamma0,\n            "gamma_multiplier": mult,\n            "rt_ratio": best_ratio,\n            "xi": best_xi,\n            "A_K": ak["A_use"],\n            "chi_eff": sol["chi_eff"],\n            "chi_ratio": sol["chi_ratio"],\n            "a_star": sol["a_star"],\n            "a_ratio": sol["a_ratio"],\n            "Gamma_req_for_rc": Gamma_req,\n            "Gamma_req_ratio": Gamma_req / Gamma0 if np.isfinite(Gamma_req) else np.nan,\n        })\n    df = pd.DataFrame(rows)\n    df.to_csv(os.path.join(OUTPUT_DIR, "v3_gamma_scan.csv"), index=False)\n\n    fig, ax = plt.subplots(1, 2, figsize=(11, 4.5))\n    ax[0].plot(df["Gamma0"] / Gamma0_nominal, df["chi_ratio"], "o-", lw=2)\n    ax[0].axhline(1.0, color="tab:red", ls="--")\n    ax[0].set_xlabel(r"$\\Gamma_0/\\Gamma_{0,nom}$")\n    ax[0].set_ylabel(r"$\\chi_{eff}/(1/2\\pi)$")\n    ax[0].grid(True, alpha=0.3)\n\n    ax[1].plot(df["Gamma0"] / Gamma0_nominal, df["a_ratio"], "o-", lw=2)\n    ax[1].axhline(1.0, color="tab:red", ls="--")\n    ax[1].set_xlabel(r"$\\Gamma_0/\\Gamma_{0,nom}$")\n    ax[1].set_ylabel(r"$a^*/r_c$")\n    ax[1].grid(True, alpha=0.3)\n    plt.tight_layout()\n    fig.savefig(os.path.join(OUTPUT_DIR, "v3_gamma_scan.png"), dpi=160, bbox_inches="tight")\n    plt.close(fig)\n    return df\n\n\ndef run_contact_sensitivity(best_ratio: float, best_xi: float) -> pd.DataFrame:\n    rows = []\n    ak = adaptive_AK(CFG.nominal_N, best_ratio, best_xi, CFG)\n    for lam in CFG.lam_values:\n        for p_exp in CFG.p_values:\n            sol = solve_stationary(ak["A_use"], ak["geom"], Gamma0_nominal, lam, p_exp)\n            rows.append({\n                "lam": lam,\n                "p": p_exp,\n                "rt_ratio": best_ratio,\n                "xi": best_xi,\n                "A_K": ak["A_use"],\n                "chi_eff": sol["chi_eff"],\n                "chi_ratio": sol["chi_ratio"],\n                "a_ratio": sol["a_ratio"],\n                "contact_ratio": sol["contact_ratio"],\n            })\n    df = pd.DataFrame(rows)\n    df.to_csv(os.path.join(OUTPUT_DIR, "v3_contact_sensitivity.csv"), index=False)\n\n    fig, ax = plt.subplots(figsize=(7.5, 4.5))\n    for p_exp in sorted(df["p"].unique()):\n        sub = df[df["p"] == p_exp].sort_values("lam")\n        ax.plot(sub["lam"], sub["chi_ratio"], "o-", lw=2, label=f"p={p_exp}")\n    ax.axhline(1.0, color="tab:red", ls="--")\n    ax.set_xlabel(r"$\\lambda_K$")\n    ax.set_ylabel(r"$\\chi_{eff}/(1/2\\pi)$")\n    ax.set_title("Contact-barrier sensitivity")\n    ax.grid(True, alpha=0.3)\n    ax.legend()\n    plt.tight_layout()\n    fig.savefig(os.path.join(OUTPUT_DIR, "v3_contact_sensitivity.png"), dpi=160, bbox_inches="tight")\n    plt.close(fig)\n    return df\n\n\nprint("=" * 72)\nprint("SST TREFOIL V3 — HARDER OPTION-B TEST")\nprint("=" * 72)\nprint(f"FAST_MODE            = {FAST_MODE}")\nprint(f"Output directory     = {OUTPUT_DIR}")\nprint(f"Gamma0_nominal       = {Gamma0_nominal:.9e} m^2/s")\nprint(f"alpha_SST^-1         = {1.0/alpha_SST:.9f}")\nprint(f"Target chi_req       = {chi_req:.9f} = 1/(2*pi)")\nprint(f"Target A_req         = {A_req:.9f} = 1/(4*pi)")\nprint()\n\nnom = run_nominal_diagnostic()\ndf_N = run_N_convergence()\ndf_opt = run_ratio_optimisation()\nbest = df_opt.iloc[0]\ndf_gamma = run_gamma_scan(float(best["rt_ratio"]), float(best["xi"]))\ndf_contact = run_contact_sensitivity(float(best["rt_ratio"]), float(best["xi"]))\n\nsummary_lines = []\nsummary_lines.append("SST Trefoil V3 summary")\nsummary_lines.append("=" * 40)\nsummary_lines.append(f"FAST_MODE: {FAST_MODE}")\nsummary_lines.append(f"Nominal A_K: {nom[\'A_use\']:.9f}")\nsummary_lines.append(f"Nominal A_ratio: {nom[\'A_use\']/A_req:.9f}")\nsummary_lines.append(f"Nominal chi_eff: {nom[\'chi_eff\']:.9f}")\nsummary_lines.append(f"Nominal chi_ratio: {nom[\'chi_ratio\']:.9f}")\nsummary_lines.append(f"Nominal a*/r_c: {nom[\'a_ratio\']:.9f}")\nsummary_lines.append(f"Nominal plateau relstd: {nom[\'plateau_relstd\']:.9f}")\nsummary_lines.append("")\nsummary_lines.append("Best (R_t/r_t, xi) from objective scan:")\nsummary_lines.append(best.to_string())\nsummary_lines.append("")\nsummary_lines.append("N convergence:")\nsummary_lines.append(df_N.to_string(index=False))\nsummary_lines.append("")\nsummary_lines.append("Gamma scan:")\nsummary_lines.append(df_gamma.to_string(index=False))\nsummary_lines.append("")\nsummary_lines.append("Contact sensitivity:")\nsummary_lines.append(df_contact.to_string(index=False))\n\nsummary_text = "\\n".join(summary_lines)\nwith open(os.path.join(OUTPUT_DIR, "v3_summary.txt"), "w", encoding="utf-8") as f:\n    f.write(summary_text)\n\nprint(summary_text)\n'


def run_block(name: str, src: str, fast: bool = False):
    print("\n" + "=" * 90)
    print(f"RUNNING {name} BLOCK")
    print("=" * 90)
    ns = {"__name__": "__main__", "FAST_MODE": fast}
    exec(compile(src, f"<{name.lower()}>", "exec"), ns, ns)


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--mode", choices=["baseline", "sweep", "advanced", "both", "all"], default="all")
    parser.add_argument("--fast", action="store_true", help="lighter advanced-block settings for smoke tests")
    args = parser.parse_args()

    if args.mode == "baseline":
        run_block("BASELINE", BASELINE_SCRIPT, fast=args.fast)
    elif args.mode == "sweep":
        run_block("SWEEP", SWEEP_SCRIPT, fast=args.fast)
    elif args.mode == "advanced":
        run_block("ADVANCED", ADVANCED_SCRIPT, fast=args.fast)
    elif args.mode == "both":
        run_block("BASELINE", BASELINE_SCRIPT, fast=args.fast)
        run_block("SWEEP", SWEEP_SCRIPT, fast=args.fast)
    elif args.mode == "all":
        run_block("BASELINE", BASELINE_SCRIPT, fast=args.fast)
        run_block("SWEEP", SWEEP_SCRIPT, fast=args.fast)
        run_block("ADVANCED", ADVANCED_SCRIPT, fast=args.fast)


if __name__ == "__main__":
    main()